CREATE DATABASE IF NOT EXISTS placement_db;
USE placement_db;
 
-- ============================================================
-- TABLE 1: Students
-- ============================================================
CREATE TABLE IF NOT EXISTS Students (
    student_id      INT             AUTO_INCREMENT PRIMARY KEY,
    full_name       VARCHAR(100)    NOT NULL,
    email           VARCHAR(150)    NOT NULL UNIQUE,
    phone           VARCHAR(15),
    department      VARCHAR(100)    NOT NULL,
    graduation_year YEAR            NOT NULL,
    cgpa            DECIMAL(4,2)    NOT NULL CHECK (cgpa BETWEEN 0.00 AND 10.00),
    backlogs        INT             DEFAULT 0,
    resume_url      VARCHAR(255),
    is_placed       BOOLEAN         DEFAULT FALSE,
    created_at      TIMESTAMP       DEFAULT CURRENT_TIMESTAMP
);
 
-- ============================================================
-- TABLE 2: Companies
-- ============================================================
CREATE TABLE IF NOT EXISTS Companies (
    company_id      INT             AUTO_INCREMENT PRIMARY KEY,
    company_name    VARCHAR(150)    NOT NULL,
    industry        VARCHAR(100),
    website         VARCHAR(255),
    hr_name         VARCHAR(100),
    hr_email        VARCHAR(150),
    hr_phone        VARCHAR(15),
    is_approved     BOOLEAN         DEFAULT FALSE,
    created_at      TIMESTAMP       DEFAULT CURRENT_TIMESTAMP
);
 
-- ============================================================
-- TABLE 3: Job_Postings
-- ============================================================
CREATE TABLE IF NOT EXISTS Job_Postings (
    job_id              INT             AUTO_INCREMENT PRIMARY KEY,
    company_id          INT             NOT NULL,
    job_title           VARCHAR(150)    NOT NULL,
    job_description     TEXT,
    location            VARCHAR(150),
    job_type            ENUM('Full-Time','Internship','Contract') DEFAULT 'Full-Time',
    ctc_fixed           DECIMAL(10,2),
    ctc_variable        DECIMAL(10,2)   DEFAULT 0.00,
    min_cgpa            DECIMAL(4,2)    DEFAULT 0.00,
    eligible_depts      TEXT,
    eligible_grad_years TEXT,
    openings            INT             DEFAULT 1,
    application_deadline DATE,
    is_approved         BOOLEAN         DEFAULT FALSE,
    created_at          TIMESTAMP       DEFAULT CURRENT_TIMESTAMP,
 
    CONSTRAINT fk_jp_company FOREIGN KEY (company_id)
        REFERENCES Companies(company_id) ON DELETE CASCADE
);
 
-- ============================================================
-- TABLE 4: Skills
-- ============================================================
CREATE TABLE IF NOT EXISTS Skills (
    skill_id    INT             AUTO_INCREMENT PRIMARY KEY,
    skill_name  VARCHAR(100)    NOT NULL UNIQUE,
    skill_type  ENUM('Technical','Soft','Domain') DEFAULT 'Technical'
);
 
-- ============================================================
-- TABLE 5: Skill_Mappings
-- ============================================================
CREATE TABLE IF NOT EXISTS Skill_Mappings (
    mapping_id      INT         AUTO_INCREMENT PRIMARY KEY,
    skill_id        INT         NOT NULL,
    entity_type     ENUM('Student','Job') NOT NULL,
    entity_id       INT         NOT NULL,
    proficiency     ENUM('Beginner','Intermediate','Advanced') DEFAULT NULL,
 
    CONSTRAINT fk_sm_skill FOREIGN KEY (skill_id)
        REFERENCES Skills(skill_id) ON DELETE CASCADE,
 
    UNIQUE KEY uq_skill_entity (skill_id, entity_type, entity_id)
);
 
-- ============================================================
-- TABLE 6: Student_Projects
-- ============================================================
CREATE TABLE IF NOT EXISTS Student_Projects (
    project_id      INT             AUTO_INCREMENT PRIMARY KEY,
    student_id      INT             NOT NULL,
    project_title   VARCHAR(200)    NOT NULL,
    description     TEXT,
    technologies    VARCHAR(255),
    project_url     VARCHAR(255),
    start_date      DATE,
    end_date        DATE,
 
    CONSTRAINT fk_sp_student FOREIGN KEY (student_id)
        REFERENCES Students(student_id) ON DELETE CASCADE
);
 
-- ============================================================
-- TABLE 7: Internships
-- ============================================================
CREATE TABLE IF NOT EXISTS Internships (
    internship_id   INT             AUTO_INCREMENT PRIMARY KEY,
    student_id      INT             NOT NULL,
    company_name    VARCHAR(150)    NOT NULL,
    role            VARCHAR(100),
    start_date      DATE            NOT NULL,
    end_date        DATE,
    stipend         DECIMAL(10,2),
    description     TEXT,
 
    CONSTRAINT fk_int_student FOREIGN KEY (student_id)
        REFERENCES Students(student_id) ON DELETE CASCADE
);
 
-- ============================================================
-- TABLE 8: Applications
-- ============================================================
CREATE TABLE IF NOT EXISTS Applications (
    application_id  INT         AUTO_INCREMENT PRIMARY KEY,
    student_id      INT         NOT NULL,
    job_id          INT         NOT NULL,
    applied_at      TIMESTAMP   DEFAULT CURRENT_TIMESTAMP,
    status          ENUM(
                        'Applied',
                        'Shortlisted',
                        'Interview_Scheduled',
                        'Selected',
                        'Rejected',
                        'Offer_Accepted',
                        'Offer_Declined'
                    ) DEFAULT 'Applied',
 
    CONSTRAINT fk_app_student FOREIGN KEY (student_id)
        REFERENCES Students(student_id) ON DELETE CASCADE,
    CONSTRAINT fk_app_job FOREIGN KEY (job_id)
        REFERENCES Job_Postings(job_id) ON DELETE CASCADE,
 
    UNIQUE KEY uq_student_job (student_id, job_id)
);
 
-- ============================================================
-- TABLE 9: Interview_Rounds
-- ============================================================
CREATE TABLE IF NOT EXISTS Interview_Rounds (
    round_id        INT         AUTO_INCREMENT PRIMARY KEY,
    application_id  INT         NOT NULL,
    round_number    INT         NOT NULL,
    round_type      ENUM('Aptitude','Technical','HR','Group Discussion','Case Study','Coding Test','Managerial') NOT NULL,
    scheduled_at    DATETIME,
    venue           VARCHAR(200),
    interviewer     VARCHAR(100),
    status          ENUM('Scheduled','Completed','Cancelled') DEFAULT 'Scheduled',
 
    CONSTRAINT fk_ir_application FOREIGN KEY (application_id)
        REFERENCES Applications(application_id) ON DELETE CASCADE,
 
    UNIQUE KEY uq_round (application_id, round_number)
);
 
-- ============================================================
-- TABLE 10: Interview_Results
-- ============================================================
CREATE TABLE IF NOT EXISTS Interview_Results (
    result_id       INT         AUTO_INCREMENT PRIMARY KEY,
    round_id        INT         NOT NULL UNIQUE,
    score           DECIMAL(5,2),
    feedback        TEXT,
    outcome         ENUM('Pass','Fail','Hold') NOT NULL,
    evaluated_at    TIMESTAMP   DEFAULT CURRENT_TIMESTAMP,
 
    CONSTRAINT fk_ires_round FOREIGN KEY (round_id)
        REFERENCES Interview_Rounds(round_id) ON DELETE CASCADE
);
 
-- ============================================================
-- TABLE 11: Placements
-- ============================================================
CREATE TABLE IF NOT EXISTS Placements (
    placement_id        INT             AUTO_INCREMENT PRIMARY KEY,
    student_id          INT             NOT NULL UNIQUE,
    application_id      INT             NOT NULL,
    ctc_fixed           DECIMAL(10,2)   NOT NULL,
    ctc_variable        DECIMAL(10,2)   DEFAULT 0.00,
    joining_date        DATE,
    offer_letter_url    VARCHAR(255),
    offer_status        ENUM('Extended','Accepted','Declined','Revoked') DEFAULT 'Extended',
    placed_at           TIMESTAMP       DEFAULT CURRENT_TIMESTAMP,
 
    CONSTRAINT fk_pl_student FOREIGN KEY (student_id)
        REFERENCES Students(student_id) ON DELETE CASCADE,
    CONSTRAINT fk_pl_application FOREIGN KEY (application_id)
        REFERENCES Applications(application_id) ON DELETE CASCADE
);
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS Users (
    user_id      INT           AUTO_INCREMENT PRIMARY KEY,
    username     VARCHAR(100)  NOT NULL UNIQUE,
    password_hash VARCHAR(255) NOT NULL,
    role         ENUM('student', 'company', 'admin') NOT NULL,
    entity_id    INT           DEFAULT NULL,
    -- entity_id links to student_id (if role=student)
    -- or company_id (if role=company)
    -- or NULL (if role=admin)
    created_at   TIMESTAMP     DEFAULT CURRENT_TIMESTAMP
);
 
